class Solution:
    def reverseByType(self, s):
        specials = set('!@#$%^&*()')
        chars = list(s)
        i, j = 0, len(chars) - 1
        while i < j:
            while i < j and chars[i] in specials:
                i += 1
            while i < j and chars[j] in specials:
                j -= 1
            if i < j:
                chars[i], chars[j] = chars[j], chars[i]
                i += 1
                j -= 1
        i, j = 0, len(chars) - 1
        while i < j:
            while i < j and chars[i] not in specials:
                i += 1
            while i < j and chars[j] not in specials:
                j -= 1
            if i < j:
                chars[i], chars[j] = chars[j], chars[i]
                i += 1
                j -= 1
        return ''.join(chars)

