class Solution:
    def reverseByType(self, s):
        specials = set('!@#$%^&*()')
        chars = list(s)
        letter_positions = [i for i, ch in enumerate(chars) if ch not in specials]
        special_positions = [i for i, ch in enumerate(chars) if ch in specials]
        letters = [chars[i] for i in letter_positions][::-1]
        specials_list = [chars[i] for i in special_positions][::-1]
        for pos, ch in zip(letter_positions, letters):
            chars[pos] = ch
        for pos, ch in zip(special_positions, specials_list):
            chars[pos] = ch
        return ''.join(chars)

