var reverseByType = function(s) {
    const specials = new Set('!@#$%^&*()'.split(''));
    const chars = s.split('');
    const letterPositions = [];
    const specialPositions = [];
    for (let i = 0; i < chars.length; i++) {
        if (specials.has(chars[i])) specialPositions.push(i);
        else letterPositions.push(i);
    }
    const letters = letterPositions.map(i => chars[i]).reverse();
    const specialChars = specialPositions.map(i => chars[i]).reverse();
    letterPositions.forEach((pos, idx) => { chars[pos] = letters[idx]; });
    specialPositions.forEach((pos, idx) => { chars[pos] = specialChars[idx]; });
    return chars.join('');
};
